SELECT p.*, o.member_nm, o.order_date, m.member_email, cd_ps.code_label AS pay_status_cd_nm, cd_pm.code_label AS pay_method_cd_nm, cd_pd.code_label AS pay_dir_cd_nm, cd_rs.code_label AS refund_status_cd_nm FROM od_pay p LEFT JOIN od_order o ON o.order_id = p.order_id LEFT JOIN mb_member m ON m.member_id = o.member_id LEFT JOIN sy_code cd_ps ON cd_ps.code_grp = 'PAY_STATUS' AND cd_ps.code_value = p.pay_status_cd LEFT JOIN sy_code cd_pm ON cd_pm.code_grp = 'PAY_METHOD' AND cd_pm.code_value = p.pay_method_cd LEFT JOIN sy_code cd_pd ON cd_pd.code_grp = 'PAY_DIR' AND cd_pd.code_value = p.pay_dir_cd LEFT JOIN sy_code cd_rs ON cd_rs.code_grp = 'REFUND_STATUS' AND cd_rs.code_value = p.refund_status_cd
ORDER BY p.pay_id ASC ORDER BY p.pay_id DESC ORDER BY p.vbank_bank_nm ASC ORDER BY p.vbank_bank_nm DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT p.*, o.member_nm, o.order_date, m.member_email, cd_ps.code_label AS pay_status_cd_nm, cd_pm.code_label AS pay_method_cd_nm, cd_pd.code_label AS pay_dir_cd_nm, cd_rs.code_label AS refund_status_cd_nm FROM od_pay p LEFT JOIN od_order o ON o.order_id = p.order_id LEFT JOIN mb_member m ON m.member_id = o.member_id LEFT JOIN sy_code cd_ps ON cd_ps.code_grp = 'PAY_STATUS' AND cd_ps.code_value = p.pay_status_cd LEFT JOIN sy_code cd_pm ON cd_pm.code_grp = 'PAY_METHOD' AND cd_pm.code_value = p.pay_method_cd LEFT JOIN sy_code cd_pd ON cd_pd.code_grp = 'PAY_DIR' AND cd_pd.code_value = p.pay_dir_cd LEFT JOIN sy_code cd_rs ON cd_rs.code_grp = 'REFUND_STATUS' AND cd_rs.code_value = p.refund_status_cd
ORDER BY p.pay_id ASC ORDER BY p.pay_id DESC ORDER BY p.vbank_bank_nm ASC ORDER BY p.vbank_bank_nm DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

