UPDATE od_pay
pay_status_cd = #{payStatusCd}, pay_status_cd_before = #{payStatusCdBefore}, pay_date = #{payDate}, refund_amt = #{refundAmt}, refund_status_cd = #{refundStatusCd}, refund_date = #{refundDate}, memo = #{memo}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE pay_id = #{payId}
